INSERT INTO `journal_encounter_section` (`ID`, `Title`, `BodyText`, `JournalEncounterID`, `OrderIndex`, `ParentSectionID`, `FirstChildSectionID`, `NextSiblingSectionID`, `Type`, `IconCreatureDisplayInfoID`, `UiModelSceneID`, `SpellID`, `IconFileDataID`, `Flags`, `IconFlags`, `DifficultyMask`, `VerifiedBuild`) VALUES
(32672, 'Tanks', '$bullet; The Hoardmonger gathers from the nearest resource pile during |cFF2959D3|Hspell:1235072|h[Resourceful Measures]|h|r.\n$bullet; Rotten Mushrooms apply |cFF2959D3|Hspell:1234846|h[Toxic Spores]|h|r upon contact, preventing them from detonating in a |cFF2959D3|Hspell:1245593|h[Putrid Burst]|h|r.\n$bullet; |cFF2959D3|Hspell:1234681|h[Ravenous Bellow]|h|r and |cFF2959D3|Hspell:1235125|h[Hearty Bellow]|h|r inflict high damage to all players.', 2776, 4, 32669, 0, 0, 3, 0, 0, 0, 0, 0, 1, -1, 67186),
(32669, 'Overview', 'The Hoardmonger prevents his reserves from being pilfered at all costs, casting |cFF2959D3|Hspell:1235072|h[Resourceful Measures]|h|r upon reaching 90%, 60%, and 30% health, empowering one of his abilities.\n\nUpon reaching 100 energy, he tosses |cFF2959D3|Hspell:1234233|h[Spoiled Supplies]|h|r throughout the arena, growing Rotten Mushrooms for 12 seconds. Upon contact, these apply |cFF2959D3|Hspell:1234846|h[Toxic Spores]|h|r destroying the fungi, preventing |cFF2959D3|Hspell:1245593|h[Putrid Burst]|h|r.', 2776, 1, 0, 32670, 32673, 3, 0, 0, 0, 0, 0, 0, -1, 67186),
(31527, 'Forbidden Freight', 'A shipment meant to be kept hidden from prying eyes. Provides an excellent source of cover.', 2680, 7, 31526, 34475, 0, 1, 137176, 0, 0, 0, 0, 0, -1, 67186),
(31282, 'Tank', '$bullet; Kystia turns Nibbles hostile to players with |cFF2959D3|Hspell:1230289|h[Illicit Infusion]|h|r.\n$bullet; Avoid Nibbles\' |cFF2959D3|Hspell:1253811|h[Fel Spray]|h|r.\n$bullet; Interrupt Kystia\'s |cFF2959D3|Hspell:1264095|h[Mirror Images]|h|r.', 2679, 4, 31279, 0, 0, 3, 0, 0, 0, 0, 0, 1, -1, 67186),
(31281, 'Healers', '$bullet; Kystia turns Nibbles hostile to players with |cFF2959D3|Hspell:1230289|h[Illicit Infusion]|h|r.\n$bullet; Avoid Nibbles\' |cFF2959D3|Hspell:1253811|h[Fel Spray]|h|r.\n$bullet; Kystia inflicts heavy damage to all players while |cFF2959D3|Hspell:1265412|h[Destabilized]|h|r.', 2679, 3, 31279, 0, 31282, 3, 0, 0, 0, 0, 0, 4, -1, 67186),
(31280, 'Damage Dealers', '$bullet; Kystia turns Nibbles hostile to players with |cFF2959D3|Hspell:1230289|h[Illicit Infusion]|h|r.\n$bullet; Avoid Nibbles\' |cFF2959D3|Hspell:1253811|h[Fel Spray]|h|r.\n$bullet; Interrupt Kystia\'s |cFF2959D3|Hspell:1264095|h[Mirror Images]|h|r.', 2679, 2, 31279, 0, 31281, 3, 0, 0, 0, 0, 0, 2, -1, 67186),
(35862, 'Section 18', '', 2870, 9, 35353, 0, 0, 2, 0, 0, 1295986, 0, 1, 0, -1, 67186),
(35353, 'Section 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 2870, 8, 0, 35862, 34729, 2, 0, 0, 1284818, 0, 1, 0, -1, 67186),
(34751, 'Section 17', '', 2870, 11, 34729, 0, 34722, 2, 140396, 0, 1272893, 0, 0, 0, -1, 67186),
(34733, 'Xal\'atath\'s Guile', 'Xal\'atath betrays players, revoking her bargains while making deaths subtract 15 seconds from time remaining.', 2870, 18, 0, 0, 0, 2, 0, 0, 0, 1723989, 1, 0, -1, 67186),
(34732, 'Fortified', 'Non-boss enemies have 20% more health and inflict up to 20% increased damage.', 2870, 17, 34730, 0, 0, 2, 0, 0, 0, 463829, 0, 0, -1, 67186),
(34731, 'Tyrannical', 'Bosses have 25% more health. Bosses and their minions inflict up to 15% increased damage.', 2870, 16, 34730, 0, 34732, 2, 0, 0, 0, 236401, 0, 0, -1, 67186),
(34730, 'Tyrannical and Fortified', 'These affixes further empower enemies in Mythic Keystone dungeons. One becomes active at Mythic Level 7 and the other at Mythic Level 10, rotating each week.', 2870, 15, 0, 34731, 34733, 2, 0, 0, 0, 135901, 1, 0, -1, 67186),
