(34722, 'Xal\'atath\'s Bargain: Pulsar', '', 2870, 12, 34729, 0, 34725, 2, 141206, 0, 1272894, 4914667, 0, 0, -1, 67186),
(34720, 'Mythic Level 6', '$bullet;|cFF2959D3|Hspell:1284818|h[Lindormi\'s Guidance]|h|r is removed.\n\nCharacters with a tank specialization can speak with Lindormi near the The Timeways portal or at the end of a Keystone Dungeon to gain |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r, which will continue to highlight enemy forces.', 2870, 7, 34716, 0, 0, 3, 0, 0, 0, 0, 0, 0, -1, 67186),
