INSERT INTO `mail_template` (`ID`, `Body`, `VerifiedBuild`) VALUES
(659, 'Greetings, acolyte!\n\nBehold the wonder of this domain overflowing with GLORIOUS ABUNDANCE! It surges, it swells, it rejects all containment!\n\nYour devotion to my divine self is deserving of some small benevolence. This time, in the form of Unalloyed Abundance!\n\nAnd take note, gracious acolyte: Certain offerings, such as Fused Vitality, will now appear amongst other purveyors. Perhaps you will encounter them, should your escapades ever pass near the Zul\'Aman Depths.\n\nMarvelous harvests to you,\n\n-Dundun, Loa of Abundance', 67186);
